sql:
SELECT city_id, fuel_type_id, AVG(price) AS average_price
FROM city_fuel_prices
GROUP BY city_id, fuel_type_id;

SELECT average_quality, min_quality, max_quality
FROM fuel_quality_trends
WHERE fuel_type_id = 1 AND city_id = 0;

SELECT AVG(average_quality) AS average_quality, MIN(min_quality) AS min_quality, MAX(max_quality) AS max_quality
FROM fuel_quality_trends
WHERE fuel_type_id = 1 AND city_id = 0;

SELECT AVG(average_price) AS avg_fuel_price
FROM price_trends
WHERE fuel_type_id = 1;

SELECT AVG(average_quality) AS avg_quality
FROM fuel_quality_trends
WHERE city_id = 1 AND fuel_type_id = 1;

SELECT MAX(price) AS max_price
FROM fuel_prices
WHERE city_id = 1;

SELECT price_threshold
FROM fuel_price_alerts
WHERE status = 'active' AND frequency = 'weekly';

SELECT COUNT(*) 
FROM fuel_quality_alerts 
WHERE fuel_type_id = 1 AND city_id = 1 AND status = 'active';

SELECT SUM(amount) AS total_amount
FROM city_fuel_prices
WHERE date = '2023-01-01';

SELECT AVG(quality) AS average_fuel_quality
FROM city_fuel_qualities
WHERE city_id = 1 AND fuel_type_id = 1;

SELECT MAX(ppg) AS max_ppg
FROM ppg
WHERE fuel_type_id = 1;

SELECT COUNT(*) 
FROM fuel_price_alerts 
WHERE status = 'active';

external_knowledge:
- The 'alert threshold' refers to a predefined price per gallon limit; 
- 'Price per gallon (PPG)' is calculated by dividing the price by the amount of fuel; 
- The 'status' column in the `fuel_price_alerts` table indicates whether a fuel price alert is active or not.
